style.css: /** * I saw a pen from Ryan Mulligan using GSAP’s ScrollTrigger * and wanted to see if I could get something similar * running with pure CSS. * * @see https://codepen.io/hexagoncircle/pen/gOPMwvd */ @keyframes highlight { 	to { 		background-position: 0; 	} } mark { 	animation: highlight linear forwards; 	animation-timeline: view(60% 20%); 	background: linear-gradient( 		to right, 		oklch(0.86 0.19 84.89 / 1) 50%, 		oklch(0.86 0.19 84.89 / 0) 50% 	); 	background-position: 100%; 	background-size: 200% 100%; 	border-radius: 0.125rem; 	padding-inline: 0.125rem; } /************************************************ * Other styles to make the demo look nice. ***********************************************/ * { 	box-sizing: border-box; } html { 	color: oklch(0.2 0.19 84.89 / 1); 	font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, 		Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol"; 	font-size: 24px; 	line-height: 1.45; } body { 	margin: 0; } article { 	display: grid; 	min-height: 100svh; 	place-items: center; 	width: 100%; 	& .content { 		padding-block: 2rem 30svh; 		width: min(600px, 90vw); 	} 	& img { 		background-color: oklch(0.8 0.16 86.85 / 1); 		object-fit: contain; 		height: min(60dvb, 60dvi); 		width: 100%; 	} } :is(h1, h2) { 	margin: 0; 	line-height: 1.1; } h2 { 	margin-block-start: 2rem; }
